Функция ОбъединитьИнтервалы(Интервалы) Экспорт

    Таблица = Новый ТаблицаЗначений;
    Таблица.Колонки.Добавить("Начало");
    Таблица.Колонки.Добавить("Конец");

    Для каждого Интервал Из Интервалы Цикл
        СтрокаТЗ = Таблица.Добавить();
        СтрокаТЗ.Начало = Интервал[0];
        СтрокаТЗ.Конец = Интервал[1];
    КонецЦикла;

    Таблица.Сортировать("Начало");

    Результат = Новый Массив;

    Для каждого СтрокаТЗ Из Таблица Цикл
        Если Результат.Количество() = 0 Тогда
            НовыйИнт = Новый Массив;
            НовыйИнт.Добавить(СтрокаТЗ.Начало);
            НовыйИнт.Добавить(СтрокаТЗ.Конец);
            Результат.Добавить(НовыйИнт);
        Иначе
            Последний = Результат[Результат.Количество() - 1];
