        Интервал = Отсортированные[i];
        Если Интервал[0] <= ТекущийКонец + 1 Тогда
            // Интервалы пересекаются или соприкасаются
            Если Интервал[1] > ТекущийКонец Тогда
                ТекущийКонец = Интервал[1];
