            Результат.Добавить(НовыйИнтервал);
            ТекущееНачало = Интервал[0];
            ТекущийКонец = Интервал[1];
        КонецЕсли;
    КонецЦикла;

    // Добавляем последний интервал
    НовыйИнтервал = Новый Массив;
    НовыйИнтервал.Добавить(ТекущееНачало);
    НовыйИнтервал.Добавить(ТекущийКонец);
    Результат.Добавить(НовыйИнтервал);

    Возврат Результат;
