    Для Каждого Интервал Из Интервалы Цикл
        НоваяСтрока = ТаблицаИнтервалов.Добавить();
        НоваяСтрока.Начало = Интервал[0];
        НоваяСтрока.Конец = Интервал[1];
    КонецЦикла;

    ТаблицаИнтервалов.Сортировать("Начало Возр, Конец Возр");

    ТекущееНачало = Неопределено;
    ТекущийКонец = Неопределено;

    Для Каждого Строка Из ТаблицаИнтервалов Цикл

        Если ТекущееНачало = Неопределено Тогда
            ТекущееНачало = Строка.Начало;
            ТекущийКонец = Строка.Конец;
        Иначе

            Если Строка.Начало <= ТекущийКонец Тогда
                // Пересекается или соприкасается - объединяем
                Если Строка.Конец > ТекущийКонец Тогда
                    ТекущийКонец = Строка.Конец;
                КонецЕсли;
            Иначе
                // Не пересекается - сохраняем текущий интервал и начинаем новый
                НовыйИнтервал = Новый Массив;
                НовыйИнтервал.Добавить(ТекущееНачало);
                НовыйИнтервал.Добавить(ТекущийКонец);
                Результат.Добавить(НовыйИнтервал);

                ТекущееНачало = Строка.Начало;
                ТекущийКонец = Строка.Конец;
            КонецЕсли;

        КонецЕсли;

    КонецЦикла;

    // Добавляем последний интервал
    Если ТекущееНачало <> Неопределено Тогда
        НовыйИнтервал = Новый Массив;
        НовыйИнтервал.Добавить(ТекущееНачало);
        НовыйИнтервал.Добавить(ТекущийКонец);
        Результат.Добавить(НовыйИнтервал);
    КонецЕсли;

    Возврат Результат;

