Функция ОбъединитьИнтервалы(Интервалы) Экспорт

	ОтсортированныеИнтервалы = Новый Массив;

	Для Каждого Интервал Из Интервалы Цикл
		НовыйИнтервал = Новый Массив;
		НовыйИнтервал.Добавить(Интервал[0]);
		НовыйИнтервал.Добавить(Интервал[1]);
		ОтсортированныеИнтервалы.Добавить(НовыйИнтервал);
	КонецЦикла;

	Если ОтсортированныеИнтервалы.Количество() = 0 Тогда
		Возврат Новый Массив;
	КонецЕсли;

	Для Индекс = 1 По ОтсортированныеИнтервалы.Количество() - 1 Цикл

		ТекущийИнтервал = ОтсортированныеИнтервалы[Индекс];
		Позиция = Индекс - 1;

		Пока Позиция >= 0 Цикл

			ПредыдущийИнтервал = ОтсортированныеИнтервалы[Позиция];

			Если ПредыдущийИнтервал[0] < ТекущийИнтервал[0]
				Или (ПредыдущийИнтервал[0] = ТекущийИнтервал[0]
					И ПредыдущийИнтервал[1] <= ТекущийИнтервал[1]) Тогда
				Прервать;
			КонецЕсли;

			ОтсортированныеИнтервалы[Позиция + 1] = ПредыдущийИнтервал;
			Позиция = Позиция - 1;

		КонецЦикла;

		ОтсортированныеИнтервалы[Позиция + 1] = ТекущийИнтервал;

	КонецЦикла;

	Результат = Новый Массив;
	ТекущийИнтервал = Новый Массив;
	ТекущийИнтервал.Добавить(ОтсортированныеИнтервалы[0][0]);
	ТекущийИнтервал.Добавить(ОтсортированныеИнтервалы[0][1]);

	Для Индекс = 1 По ОтсортированныеИнтервалы.Количество() - 1 Цикл

		СледующийИнтервал = ОтсортированныеИнтервалы[Индекс];

		Если СледующийИнтервал[0] <= ТекущийИнтервал[1] Тогда

			Если СледующийИнтервал[1] > ТекущийИнтервал[1] Тогда
				ТекущийИнтервал[1] = СледующийИнтервал[1];
			КонецЕсли;

		Иначе

			Результат.Добавить(ТекущийИнтервал);

			ТекущийИнтервал = Новый Массив;
			ТекущийИнтервал.Добавить(СледующийИнтервал[0]);
			ТекущийИнтервал.Добавить(СледующийИнтервал[1]);

		КонецЕсли;

	КонецЦикла;

	Результат.Добавить(ТекущийИнтервал);

	Возврат Результат;

КонецФункции

Функция ОбъединитьИнтервалы(Интервалы) Экспорт

	ОтсортированныеИнтервалы = Новый Массив;

	Для Каждого Интервал Из Интервалы Цикл
		КопияИнтервала = Новый Массив;
		КопияИнтервала.Добавить(Интервал[0]);
		КопияИнтервала.Добавить(Интервал[1]);
		ОтсортированныеИнтервалы.Добавить(КопияИнтервала);
	КонецЦикла;

	КоличествоИнтервалов = ОтсортированныеИнтервалы.Количество();

	Если КоличествоИнтервалов > 1 Тогда
		Для Индекс = 0 По КоличествоИнтервалов - 2 Цикл
			ИндексМинимального = Индекс;

			Для ИндексСравнения = Индекс + 1 По КоличествоИнтервалов - 1 Цикл
				Сравниваемый = ОтсортированныеИнтервалы[ИндексСравнения];
				Минимальный = ОтсортированныеИнтервалы[ИндексМинимального];

				Если Сравниваемый[0] < Минимальный[0]
					Или (Сравниваемый[0] = Минимальный[0]
						И Сравниваемый[1] < Минимальный[1]) Тогда
					ИндексМинимального = ИндексСравнения;
				КонецЕсли;
			КонецЦикла;

			Если ИндексМинимального <> Индекс Тогда
				ВременныйИнтервал = ОтсортированныеИнтервалы[Индекс];
				ОтсортированныеИнтервалы[Индекс] = ОтсортированныеИнтервалы[ИндексМинимального];
				ОтсортированныеИнтервалы[ИндексМинимального] = ВременныйИнтервал;
			КонецЕсли;
		КонецЦикла;
	КонецЕсли;

	Результат = Новый Массив;

	Для Каждого Интервал Из ОтсортированныеИнтервалы Цикл
		Если Результат.Количество() = 0 Тогда
			Результат.Добавить(Интервал);
			Продолжить;
		КонецЕсли;

		ПоследнийИнтервал = Результат[Результат.Количество() - 1];

		Если Интервал[0] <= ПоследнийИнтервал[1] Тогда
			Если Интервал[1] > ПоследнийИнтервал[1] Тогда
				ПоследнийИнтервал[1] = Интервал[1];
			КонецЕсли;
		Иначе
			Результат.Добавить(Интервал);
		КонецЕсли;
	КонецЦикла;

	Возврат Результат;

