Функция Левенштейн(Стр1, Стр2)

    // Оптимизация: меняем строки местами, чтобы меньшая строка была по вертикали (по столбцам)
    // Это уменьшает потребление памяти.
    Если СтрДлина(Стр1) < СтрДлина(Стр2) Тогда
        Возврат Левенштейн(Стр2, Стр1);
    КонецЕсли;

    // Инициализация предыдущей строки (расстояние от пустой строки к префиксам Стр2)
    // D[0][j] = j
    ПредыдущаяСтрока = Новый Массив;
    Для к = 0 По СтрДлина(Стр2) Цикл
        ПредыдущаяСтрока.Добавить(к);
    КонецЦикла;

    // Перебор символов первой строки
    Для i = 1 По СтрДлина(Стр1) Цикл
        // Инициализация текущей строки
        // D[i][0] = i
        ТекущаяСтрока = Новый Массив;
        ТекущаяСтрока.Добавить(i);

        Для j = 1 По СтрДлина(Стр2) Цикл
            // Стоимость замены: 0, если символы совпадают, иначе 1
            Если Сред(Стр1, i, 1) = Сред(Стр2, j, 1) Тогда
                Стоимость = 0;
            Иначе
                Стоимость = 1;
            КонецЕсли;

            // Вычисление минимума из трех операций:
            // 1. Удаление (ПредыдущаяСтрока[j] + 1)
            // 2. Вставка (ТекущаяСтрока[j-1] + 1)
            // 3. Замена (ПредыдущаяСтрока[j-1] + Стоимость)
            ТекущаяСтрока.Добавить(Мин(
                ПредыдущаяСтрока[j] + 1,
                ТекущаяСтрока[j-1] + 1,
                ПредыдущаяСтрока[j-1] + Стоимость
            ));
        КонецЦикла;

        // Переход к следующей итерации
        ПредыдущаяСтрока = ТекущаяСтрока;
