Функция РасстояниеЛевенштейна(Стр1, Стр2)
	// Подготовка длин строк
	n = СтрДлина(Стр1);
	m = СтрДлина(Стр2);
	Если n = 0 Тогда
		Возврат m;
	КонецЕсли;
	Если m = 0 Тогда
		Возврат n;
	КонецЕсли;

	// Инициализация массивов (строки +1)
	Пред = Новый Массив(m + 1);
	Тек = Новый Массив(m + 1);

	Для j = 0 По m Цикл
		Пред[j] = j;
	КонецЦикла;

	Для i = 1 По n Цикл
		Тек[0] = i;
		Для j = 1 По m Цикл
			Если Сред(Стр1, i, 1) = Сред(Стр2, j, 1) Тогда
				Стоимость = 0;
			Иначе
				Стоимость = 1;
			КонецЕсли;

			Удаление = Пред[j] + 1;
			Вставка = Тек[j - 1] + 1;
			Замена = Пред[j - 1] + Стоимость;

			Тек[j] = Мин(Мин(Удаление, Вставка), Замена);
		КонецЦикла;

		// Поменять местами Пред и Тек
		Врем = Пред;
		Пред = Тек;
		Тек = Врем;
	КонецЦикла;

	Возврат Пред[m];
