Функция РасстояниеЛевенштейна(ПерваяСтрока, ВтораяСтрока) Экспорт

	ДлинаПервойСтроки = СтрДлина(ПерваяСтрока);
	ДлинаВторойСтроки = СтрДлина(ВтораяСтрока);

	ПредыдущаяСтрока = Новый Массив;
	ТекущаяСтрока = Новый Массив;

	Для ИндексВторойСтроки = 0 По ДлинаВторойСтроки Цикл
		ПредыдущаяСтрока.Добавить(ИндексВторойСтроки);
		ТекущаяСтрока.Добавить(0);
	КонецЦикла;

	Для ИндексПервойСтроки = 1 По ДлинаПервойСтроки Цикл

		ТекущаяСтрока[0] = ИндексПервойСтроки;
		СимволПервойСтроки = Сред(ПерваяСтрока, ИндексПервойСтроки, 1);

		Для ИндексВторойСтроки = 1 По ДлинаВторойСтроки Цикл

			Если СимволПервойСтроки = Сред(ВтораяСтрока, ИндексВторойСтроки, 1) Тогда
				СтоимостьЗамены = 0;
			Иначе
				СтоимостьЗамены = 1;
			КонецЕсли;

			СтоимостьУдаления = ПредыдущаяСтрока[ИндексВторойСтроки] + 1;
			СтоимостьВставки = ТекущаяСтрока[ИндексВторойСтроки - 1] + 1;
			СтоимостьЗаменыСимвола = ПредыдущаяСтрока[ИндексВторойСтроки - 1] + СтоимостьЗамены;

			ТекущаяСтрока[ИндексВторойСтроки] = Мин(СтоимостьУдаления, СтоимостьВставки, СтоимостьЗаменыСимвола);

		КонецЦикла;

		ВременнаяСтрока = ПредыдущаяСтрока;
		ПредыдущаяСтрока = ТекущаяСтрока;
		ТекущаяСтрока = ВременнаяСтрока;

	КонецЦикла;

	Возврат ПредыдущаяСтрока[ДлинаВторойСтроки];

КонецФункции

Функция РасстояниеЛевенштейна(ПерваяСтрока, ВтораяСтрока) Экспорт

	ДлинаПервойСтроки = СтрДлина(ПерваяСтрока);
	ДлинаВторойСтроки = СтрДлина(ВтораяСтрока);

	Если ДлинаПервойСтроки = 0 Тогда
		Возврат ДлинаВторойСтроки;
	КонецЕсли;

	Если ДлинаВторойСтроки = 0 Тогда
		Возврат ДлинаПервойСтроки;
	КонецЕсли;

	ПредыдущаяСтрока = Новый Массив(ДлинаВторойСтроки + 1);
	ТекущаяСтрока = Новый Массив(ДлинаВторойСтроки + 1);

	Для НомерСимвола = 0 По ДлинаВторойСтроки Цикл
		ПредыдущаяСтрока[НомерСимвола] = НомерСимвола;
	КонецЦикла;

	Для НомерПервогоСимвола = 1 По ДлинаПервойСтроки Цикл

		ТекущаяСтрока[0] = НомерПервогоСимвола;
		ПервыйСимвол = Сред(ПерваяСтрока, НомерПервогоСимвола, 1);

		Для НомерВторогоСимвола = 1 По ДлинаВторойСтроки Цикл

			ВторойСимвол = Сред(ВтораяСтрока, НомерВторогоСимвола, 1);

			Если ПервыйСимвол = ВторойСимвол Тогда
				СтоимостьЗамены = 0;
			Иначе
				СтоимостьЗамены = 1;
			КонецЕсли;

			СтоимостьУдаления = ПредыдущаяСтрока[НомерВторогоСимвола] + 1;
			СтоимостьВставки = ТекущаяСтрока[НомерВторогоСимвола - 1] + 1;
			СтоимостьЗаменыСимвола = ПредыдущаяСтрока[НомерВторогоСимвола - 1] + СтоимостьЗамены;

			МинимальнаяСтоимость = СтоимостьУдаления;

			Если СтоимостьВставки < МинимальнаяСтоимость Тогда
				МинимальнаяСтоимость = СтоимостьВставки;
			КонецЕсли;

			Если СтоимостьЗаменыСимвола < МинимальнаяСтоимость Тогда
				МинимальнаяСтоимость = СтоимостьЗаменыСимвола;
			КонецЕсли;

			ТекущаяСтрока[НомерВторогоСимвола] = МинимальнаяСтоимость;

		КонецЦикла;

		БуфернаяСтрока = ПредыдущаяСтрока;
		ПредыдущаяСтрока = ТекущаяСтрока;
		ТекущаяСтрока = БуфернаяСтрока;

	КонецЦикла;

	Возврат ПредыдущаяСтрока[ДлинаВторойСтроки];

