Функция ЯвляютсяАнаграммами(Строка1, Строка2) Экспорт

	Строка1 = СтрЗаменить(НРег(Строка1), " ", "");
	Строка2 = СтрЗаменить(НРег(Строка2), " ", "");

	Если СтрДлина(Строка1) <> СтрДлина(Строка2) Тогда
		Возврат Ложь;
	КонецЕсли;

	Счетчики = Новый Соответствие;

	Для Индекс = 1 По СтрДлина(Строка1) Цикл
		Символ = Сред(Строка1, Индекс, 1);
		Количество = Счетчики.Получить(Символ);

		Если Количество = Неопределено Тогда
			Счетчики.Вставить(Символ, 1);
		Иначе
			Счетчики.Вставить(Символ, Количество + 1);
		КонецЕсли;
	КонецЦикла;

	Для Индекс = 1 По СтрДлина(Строка2) Цикл
		Символ = Сред(Строка2, Индекс, 1);
		Количество = Счетчики.Получить(Символ);

		Если Количество = Неопределено Или Количество = 0 Тогда
			Возврат Ложь;
		КонецЕсли;

		Счетчики.Вставить(Символ, Количество - 1);
	КонецЦикла;

	Возврат Истина;

КонецФункции

Функция ЯвляютсяАнаграммами(Строка1, Строка2) Экспорт
    Если Строка1 = Неопределено Или Строка2 = Неопределено Тогда
        Возврат Ложь;
    КонецЕсли;

    S1 = НижнийРегистр(СтрЗаменить(Строка1, " ", ""));
    S2 = НижнийРегистр(СтрЗаменить(Строка2, " ", ""));

    Если СтрДлина(S1) <> СтрДлина(S2) Тогда
        Возврат Ложь;
    КонецЕсли;

    Счеты = Новый Соответствие;

    Для i = 1 По СтрДлина(S1) Цикл
        Символ = Сред(S1, i, 1);
        Если Счеты.Содержит(Символ) Тогда
            Тек = Счеты.Получить(Символ);
            Счеты.Вставить(Символ, Тек + 1);
        Иначе
            Счеты.Вставить(Символ, 1);
        КонецЕсли;
    КонецЦикла;

    Для i = 1 По СтрДлина(S2) Цикл
        Символ = Сред(S2, i, 1);
        Если Не Счеты.Содержит(Символ) Тогда
            Возврат Ложь;
        КонецЕсли;
        Тек = Счеты.Получить(Символ) - 1;
        Если Тек < 0 Тогда
            Возврат Ложь;
        КонецЕсли;
        Счеты.Вставить(Символ, Тек);
    КонецЦикла;

    Для Каждого Пара Из Счеты Цикл
        Если Пара.Значение <> 0 Тогда
            Возврат Ложь;
        КонецЕсли;
    КонецЦикла;

    Возврат Истина;
КонецФункции

