Функция СортироватьСтроку(Стр) Экспорт
    Массив = Новый Массив;
    Для i = 1 По СтрДлина(Стр) Цикл
        Массив.Добавить(Сред(Стр, i, 1));
    КонецЦикла;
    Массив.Сортировать();
    Результат = "";
    Для каждого Символ Из Массив Цикл
        Результат = Результат + Символ;
    КонецЦикла;
    Возврат Результат;
