        Возврат Новый Массив;
    КонецЕсли;

    // Создаем массив флагов с индексами от 0 до границы включительно,
    // изначально все числа считаются простыми (истина).
    Флаги = Новый Массив(Граница + 1);
    Для i = 2 По Граница Цикл
        Флаги[i] = Истина;
    КонецЦикла;

    // Проходим по числам и помечаем кратные как составные.
    КореньИзГраницы = Цел(КвадратныйКорень(Граница));
    Для Число = 2 По КореньИзГраницы Цикл
        Если Флаги[Число] Тогда
            Шаг = Число * 2; 
            Пока Шаг <= Граница Цикл
                Флаги[Шаг] = Ложь;
                Шаг += Число;
            КонецЦикла;
        КонецЕсли;
    КонецЦикла;

    ПростыеЧисла = Новый Массив;
    Для i = 2 По Граница Цикл
        Если Флаги[i] Тогда
            ПростыеЧисла.Добавить(i);
        КонецЕсли;
    КонецЦикла;

    Возврат ПростыеЧисла;
