Функция ПростыеЧисла(Граница)
	Если Граница < 2 Тогда
		Возврат Новый Массив;
	КонецЕсли;

	Граница = Цел(Граница);
	Сеттер = Новый Массив;
	// Инициализируем массив булевых значений длиной Граница+1, все Истина
	Для Индекс = 0 По Граница Цикл
		Сеттер.Добавить(Истина);
	КонецЦикла;

	// 0 и 1 не простые
	Сеттер.Заменить(0, Ложь);
	Если Граница >= 1 Тогда
		Сеттер.Заменить(1, Ложь);
	КонецЕсли;

	Макс = Цел(КвадратныйКорень(Граница));
	Для i = 2 По Макс Цикл
		Если Не Сеттер.Получить(i) Тогда
			Продолжить;
		КонецЕсли;
		j = i * i;
		Для k = j По Граница Шаг i Цикл
			Сеттер.Заменить(k, Ложь);
		КонецЦикла;
	КонецЦикла;

	Результат = Новый Массив;
	Для i = 2 По Граница Цикл
		Если Сеттер.Получить(i) Тогда
			Результат.Добавить(i);
		КонецЕсли;
	КонецЦикла;

	Возврат Результат;
