    // Создаём массив булевых значений: Истина — число простое
    Композитные = Новый Массив(Граница + 1);
    Для Индекс = 0 По Граница Цикл
        Композитные[Индекс] = Ложь;
    КонецЦикла;

    // Алгоритм решета Эратосфена
    Делитель = 2;
    Пока Делитель * Делитель <= Граница Цикл
        Если Не Композитные[Делитель] Тогда
            Кратное = Делитель * Делитель;
            Пока Кратное <= Граница Цикл
                Композитные[Кратное] = Истина;
                Кратное = Кратное + Делитель;
            КонецЦикла;
        КонецЕсли;
        Делитель = Делитель + 1;
    КонецЦикла;

    // Собираем простые числа в результат
    Для Индекс = 2 По Граница Цикл
        Если Не Композитные[Индекс] Тогда
            Результат.Добавить(Индекс);
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;

КонецФункции
